                "type": "string",
                "enum": [
                  "accepted",
                  "denied"
                ]
              },
              "actionId": {
                "type": "string",
                "pattern": "^act_[a-z0-9][a-z0-9_-]*$"
              },
              "policyDecision": {
                "type": "string",
                "enum": [
                  "allow",
                  "deny",
                  "needs_approval",
                  "needs_owner"
                ]
              },
              "evidenceRef": {
                "type": "string",
                "pattern": "^ev_[a-z0-9][a-z0-9_-]*$"
              }
            }
          },
          "safetyConstraints": [
            "policy-required",
            "audit-required",
            "evidence-required",
            "no-inline-secret-values",
            "no-model-provided-code",
            "schema-validated-input",
            "schema-validated-output"
